# 1. Create cost allocation tags to enable per-team chargeback
az tag create --name CostCenter
az tag add-value --name CostCenter --value Engineering
az tag add-value --name CostCenter --value Marketing
az tag add-value --name CostCenter --value DataPlatform

# 2. Enforce tagging with Azure Policy (deny deployment without CostCenter tag)
az policy definition create   --name "require-costcenter-tag"   --display-name "Require CostCenter tag on resource groups"   --rules '{
    "if": {
      "allOf": [
        {"field": "type", "equals": "Microsoft.Resources/subscriptions/resourceGroups"},
        {"field": "tags[CostCenter]", "exists": "false"}
      ]
    },
    "then": {"effect": "deny"}
  }'   --mode All

az policy assignment create   --name require-costcenter-tag   --policy require-costcenter-tag   --scope /subscriptions/$SUBSCRIPTION_ID

# 3. Query current month spend grouped by CostCenter tag
az consumption usage list   --start-date $(date -d 'first day of month' +%Y-%m-01)   --end-date $(date +%Y-%m-%d)   --query 'sort_by([].{CostCenter:tags.CostCenter, Cost:pretaxCost, Resource:instanceName}, &Cost)'   --output table

# Layer 1: Management Group budget (org-wide ceiling)
az consumption budget create   --budget-name "org-total-monthly"   --amount 100000   --time-grain Monthly   --time-period-start 2025-01-01   --time-period-end 2026-01-01   --scope /providers/Microsoft.Management/managementGroups/$MG_ID   --notifications '[
    {"enabled":true,"operator":"GreaterThan","threshold":80,"contactEmails":["cto@company.com"],"thresholdType":"Actual"},
    {"enabled":true,"operator":"GreaterThan","threshold":100,"contactEmails":["cto@company.com","cfo@company.com"],"thresholdType":"Actual"}
  ]'

# Layer 2: Subscription budget per team
az consumption budget create   --budget-name "engineering-sub-monthly"   --amount 20000   --time-grain Monthly   --time-period-start 2025-01-01   --time-period-end 2026-01-01   --scope /subscriptions/$ENG_SUB_ID   --notifications '[
    {"enabled":true,"operator":"GreaterThan","threshold":75,"contactEmails":["eng-lead@company.com"],"thresholdType":"Actual"}
  ]'

# Layer 3: Resource Group budget per project
az consumption budget create   --budget-name "project-x-monthly"   --amount 3000   --time-grain Monthly   --time-period-start 2025-01-01   --time-period-end 2026-01-01   --resource-group project-x-rg   --notifications '[
    {"enabled":true,"operator":"GreaterThan","threshold":90,"contactEmails":["project-x@company.com"],"thresholdType":"Actual"}
  ]'
